import { describe, expect, it } from '@jest/globals';
import { shouldShowLoginFallbackError } from './login-error';

describe('shouldShowLoginFallbackError', () => {
  it('does not show a second login toast for HTTP errors handled by the interceptor', () => {
    expect(shouldShowLoginFallbackError({ status: 0 })).toBe(false);
    expect(shouldShowLoginFallbackError({ status: 500 })).toBe(false);
  });

  it('does not show an error when the user cancels Microsoft login', () => {
    expect(shouldShowLoginFallbackError({ errorCode: 'user_cancelled' })).toBe(false);
    expect(shouldShowLoginFallbackError({ message: 'user_cancelled' })).toBe(false);
  });

  it('shows the fallback for non-HTTP login failures', () => {
    expect(shouldShowLoginFallbackError(new Error('No idToken in Microsoft authentication result'))).toBe(true);
  });
});

