/**
 * Returns true only when every required field for creating a user is present.
 *
 * The `role` value comes from the autocomplete control, which previously was not
 * synced into the form group — see register.component. Keep this check in sync
 * with the controls declared in RegisterComponent's form group.
 */
export function hasAllRequiredUserFields(value: {
  firstName?: string;
  lastName?: string;
  email?: string;
  password?: string;
  passwordConfirm?: string;
  role?: string;
}): boolean {
  return !!(
    value &&
    value.firstName &&
    value.lastName &&
    value.email &&
    value.password &&
    value.passwordConfirm &&
    value.role
  );
}

