import { describe, expect, it } from '@jest/globals';
import { hasAllRequiredUserFields } from './register-validation';

const complete = {
  firstName: 'Albery',
  lastName: 'Test',
  email: 'u2giants@gmail.com',
  password: 'secret',
  passwordConfirm: 'secret',
  role: 'Sales',
};

describe('hasAllRequiredUserFields', () => {
  it('passes when every field is present', () => {
    expect(hasAllRequiredUserFields(complete)).toBe(true);
  });

  it('fails when the role is missing even though every visible field is filled', () => {
    // Regression: the autocomplete role value was not synced into the form group,
    // so role stayed '' and a complete-looking form was rejected.
    expect(hasAllRequiredUserFields({ ...complete, role: '' })).toBe(false);
  });

  it('fails when any other required field is missing', () => {
    expect(hasAllRequiredUserFields({ ...complete, firstName: '' })).toBe(false);
    expect(hasAllRequiredUserFields({ ...complete, email: '' })).toBe(false);
    expect(hasAllRequiredUserFields({ ...complete, passwordConfirm: '' })).toBe(false);
  });
});

