/**
 * Validation helpers for the Create New User form.
 *
 * The `role` value comes from the autocomplete control, which previously was not
 * synced into the form group — see register.component. Keep the field list here
 * in sync with the controls declared in RegisterComponent's form group.
 */

export interface NewUserFormValue {
  firstName?: string;
  lastName?: string;
  email?: string;
  password?: string;
  passwordConfirm?: string;
  role?: string;
}

/** Required fields in display order, paired with a human-readable label. */
const REQUIRED_FIELDS: ReadonlyArray<{ key: keyof NewUserFormValue; label: string }> = [
  { key: 'firstName', label: 'First Name' },
  { key: 'lastName', label: 'Last Name' },
  { key: 'email', label: 'E-Mail' },
  { key: 'password', label: 'Password' },
  { key: 'passwordConfirm', label: 'Password (Confirm)' },
  { key: 'role', label: 'Role' },
];

/** Labels of every required field left blank, in display order. */
export function missingRequiredUserFields(value: NewUserFormValue): string[] {
  if (!value) {
    return REQUIRED_FIELDS.map(field => field.label);
  }
  return REQUIRED_FIELDS.filter(field => !value[field.key]?.toString().trim()).map(
    field => field.label,
  );
}

/** Returns true only when every required field for creating a user is present. */
export function hasAllRequiredUserFields(value: NewUserFormValue): boolean {
  return missingRequiredUserFields(value).length === 0;
}

/** Joins labels into a readable list: "A", "A and B", "A, B and C". */
export function formatFieldList(labels: string[]): string {
  if (labels.length <= 1) {
    return labels.join('');
  }
  return `${labels.slice(0, -1).join(', ')} and ${labels[labels.length - 1]}`;
}

/**
 * The exact toast message to show when required fields are blank, naming each
 * one. Returns null when nothing is missing.
 */
export function missingFieldsMessage(value: NewUserFormValue): string | null {
  const missing = missingRequiredUserFields(value);
  if (missing.length === 0) {
    return null;
  }
  const noun = missing.length === 1 ? 'field' : 'fields';
  return `Please fill in the following ${noun}: ${formatFieldList(missing)}.`;
}

