import { describe, expect, it } from '@jest/globals';
import {
  formatFieldList,
  hasAllRequiredUserFields,
  missingFieldsMessage,
  missingRequiredUserFields,
} from './register-validation';

const complete = {
  firstName: 'Albery',
  lastName: 'Test',
  email: 'u2giants@gmail.com',
  password: 'secret',
  passwordConfirm: 'secret',
  role: 'Sales',
};

describe('hasAllRequiredUserFields', () => {
  it('passes when every field is present', () => {
    expect(hasAllRequiredUserFields(complete)).toBe(true);
  });

  it('fails when the role is missing even though every visible field is filled', () => {
    // Regression: the autocomplete role value was not synced into the form group,
    // so role stayed '' and a complete-looking form was rejected.
    expect(hasAllRequiredUserFields({ ...complete, role: '' })).toBe(false);
  });

  it('treats whitespace-only values as missing', () => {
    expect(hasAllRequiredUserFields({ ...complete, firstName: '   ' })).toBe(false);
  });
});

describe('missingRequiredUserFields', () => {
  it('returns nothing when the form is complete', () => {
    expect(missingRequiredUserFields(complete)).toEqual([]);
  });

  it('lists missing field labels in display order', () => {
    expect(
      missingRequiredUserFields({ ...complete, firstName: '', role: '' }),
    ).toEqual(['First Name', 'Role']);
  });

  it('lists every field when the value is null', () => {
    expect(missingRequiredUserFields(null as any)).toEqual([
      'First Name',
      'Last Name',
      'E-Mail',
      'Password',
      'Password (Confirm)',
      'Role',
    ]);
  });
});

describe('formatFieldList', () => {
  it('formats one, two, and three labels readably', () => {
    expect(formatFieldList(['Role'])).toBe('Role');
    expect(formatFieldList(['First Name', 'Role'])).toBe('First Name and Role');
    expect(formatFieldList(['First Name', 'Last Name', 'Role'])).toBe(
      'First Name, Last Name and Role',
    );
  });
});

describe('missingFieldsMessage', () => {
  it('returns null when nothing is missing', () => {
    expect(missingFieldsMessage(complete)).toBeNull();
  });

  it('names the single missing field with singular wording', () => {
    expect(missingFieldsMessage({ ...complete, role: '' })).toBe(
      'Please fill in the following field: Role.',
    );
  });

  it('names every missing field with plural wording', () => {
    expect(
      missingFieldsMessage({ ...complete, password: '', passwordConfirm: '' }),
    ).toBe('Please fill in the following fields: Password and Password (Confirm).');
  });
});

