async function makeAuthToken(email, role, route) {
  // Create token
  let token = jwt.sign(
    { email: email, role: role.toLowerCase(), route: route }, privateKey,
    {
      algorithm: 'RS256',
      expiresIn: "7days",
    }
  );
  return token;
}
async function sendSignUpEmail(email, token, role, name) {
  let signupRoute = '';
  if (role == 'vendor') {
    signupRoute = 'VendorSignUp'
  } else {
    signupRoute = 'signUp'
  }
  const webUrl = getWebUrl(undefined, undefined, { vendorHost: role == 'vendor' });
  let url = `"${webUrl}/${signupRoute}/${token}\"`
  let template = buildSignUpEmailTemplate(name, url);
  const recipients = [email];
  const subject = "Edge Home / POP Creations RFQ system account creation invitation";
  const messageId = await brevoService.sendEmail(recipients, template, subject)
  if (messageId) {
    await emailService.createEmailLog(recipients, subject, template, messageId)
  }
  return messageId;
}
Customer.sendSignUpInv = async (req, result) => {
  let email = req.body.email;
  await sql.users.findOne({
    where: {
      email: req.body.email
    }
  }).then(async (data) => {
    if (data) {
      result(null, { status: false });
    } else {
      await sql.vendor.findOne({
        where: {
          vendor_email: req.body.email,
          vendor_access: 'permanent'
        }
      }).then(async (data) => {
        if (data) {
          result(null, { status: false });
        } else {
          let token
          if (req.body.role == 'vendor') {
            token = await makeAuthToken(email, req.body.role, 'vendor_singup');
          } else {
            token = await makeAuthToken(email, req.body.role, 'sign_up');
          }
          await sql.auth_token.create({
            token: token,
            email: email,
            status: false
          }).then(async (data) => {
            await sendSignUpEmail(email, token, req.body.role, req.body.name)
            result(null, { status: true });
          }).catch(err => {
            result(err, null);
          });
        }
      }).catch(err => {
        result(err, null);
      });
    }
  }).catch(err => {
    result(err, null);
  });

}

