Customer.signup = async (req, result) => {
  req.body.password = await utility.cryptPassword(req.body.password)
  let tokenInfo = await getUserInfo(req.body.token);
  req.body.role = tokenInfo.role;
  let userInfo;

  if (req.body.role == 'vendor') {
    userInfo = await utility.remapVendor(req.body)
    await sql.vendor.update(userInfo, {
      where: {
        vendor_email: tokenInfo.email
      },
      individualHooks: true
    }).then((data) => {
      result(null, { status: true });
    }).catch(err => {
      result(err, null);
    });

  } else {
    userInfo = await utility.userInfo(req.body)
    await sql.users.findOne({
      where: {
        email: req.body.email
      }
    }).then(async (data) => {
      if (data) {
        result(null, { status: false });
      } else {
        await sql.vendor.findOne({
          where: {
            vendor_email: req.body.email
          }
        }).then(async (data) => {
          if (data) {
            result(null, { status: false });
          } else {
            await sql.users.create(userInfo)
            await sql.auth_token.update({
              status: true,
              emai: req.body.email,
              token: req.body.token
            }, {
              where: {
                token: req.body.token,
              },
              individualHooks: true
            })
            result(null, { status: true });
          }
        }).catch(err => {
          result(err, null);
        });
      }
    }).catch(err => {
      result(err, null);
    });
  }

}

