/**
 * The admin's invitation form captures a single "Name" field, but the signup
 * form asks for First Name and Last Name separately. Split the invited name on
 * the first whitespace: the first word is the first name, the remainder (if any)
 * is the last name. Both are best-effort defaults the invitee can still edit.
 */
export function splitFullName(fullName: string | null | undefined): {
  firstName: string;
  lastName: string;
} {
  const trimmed = (fullName ?? '').trim().replace(/\s+/g, ' ');
  if (!trimmed) {
    return { firstName: '', lastName: '' };
  }
  const firstSpace = trimmed.indexOf(' ');
  if (firstSpace === -1) {
    return { firstName: trimmed, lastName: '' };
  }
  return {
    firstName: trimmed.slice(0, firstSpace),
    lastName: trimmed.slice(firstSpace + 1),
  };
}

