import { describe, expect, it } from '@jest/globals';
import { splitFullName } from './signup-name';

describe('splitFullName', () => {
  it('splits a first and last name on the first space', () => {
    expect(splitFullName('Albert Testing')).toEqual({
      firstName: 'Albert',
      lastName: 'Testing',
    });
  });

  it('keeps everything after the first space as the last name', () => {
    expect(splitFullName('Mary Jane Watson')).toEqual({
      firstName: 'Mary',
      lastName: 'Jane Watson',
    });
  });

  it('uses the whole value as the first name when there is no space', () => {
    expect(splitFullName('Cher')).toEqual({ firstName: 'Cher', lastName: '' });
  });

  it('collapses extra whitespace', () => {
    expect(splitFullName('  Albert   Testing  ')).toEqual({
      firstName: 'Albert',
      lastName: 'Testing',
    });
  });

  it('returns empty strings for null, undefined, or blank input', () => {
    expect(splitFullName(null)).toEqual({ firstName: '', lastName: '' });
    expect(splitFullName(undefined)).toEqual({ firstName: '', lastName: '' });
    expect(splitFullName('   ')).toEqual({ firstName: '', lastName: '' });
  });
});

