1	/**
2	 * Validation helpers for the Create New User form.
3	 *
4	 * The `role` value comes from the autocomplete control, which previously was not
5	 * synced into the form group — see register.component. Keep the field list here
6	 * in sync with the controls declared in RegisterComponent's form group.
7	 */
8	
9	export interface NewUserFormValue {
10	  firstName?: string;
11	  lastName?: string;
12	  email?: string;
13	  password?: string;
14	  passwordConfirm?: string;
15	  role?: string;
16	}
17	
18	/** Required fields in display order, paired with a human-readable label. */
19	const REQUIRED_FIELDS: ReadonlyArray<{ key: keyof NewUserFormValue; label: string }> = [
20	  { key: 'firstName', label: 'First Name' },
21	  { key: 'lastName', label: 'Last Name' },
22	  { key: 'email', label: 'E-Mail' },
23	  { key: 'password', label: 'Password' },
24	  { key: 'passwordConfirm', label: 'Password (Confirm)' },
25	  { key: 'role', label: 'Role' },
