/**
 * Shared helpers for "which required fields are still blank" validation across
 * the auth forms (Create New User, accept-invitation signup, etc.). Each form
 * supplies its own ordered field list; the messaging is identical.
 */

export interface RequiredField<T> {
  key: keyof T;
  label: string;
}

/** Labels of every required field left blank (whitespace counts as blank), in order. */
export function missingFields<T>(
  value: T | null | undefined,
  fields: ReadonlyArray<RequiredField<T>>,
): string[] {
  if (!value) {
    return fields.map(field => field.label);
  }
  return fields
    .filter(field => !(value[field.key] as unknown)?.toString().trim())
    .map(field => field.label);
}

/** Joins labels into a readable list: "A", "A and B", "A, B and C". */
export function formatFieldList(labels: string[]): string {
  if (labels.length <= 1) {
    return labels.join('');
  }
  return `${labels.slice(0, -1).join(', ')} and ${labels[labels.length - 1]}`;
}

/**
 * The exact toast message to show when required fields are blank, naming each
 * one. Returns null when nothing is missing.
 */
export function missingFieldsMessage<T>(
  value: T | null | undefined,
  fields: ReadonlyArray<RequiredField<T>>,
): string | null {
  const missing = missingFields(value, fields);
  if (missing.length === 0) {
    return null;
  }
  const noun = missing.length === 1 ? 'field' : 'fields';
  return `Please fill in the following ${noun}: ${formatFieldList(missing)}.`;
}

