import { ChangeDetectorRef, Component, OnInit, Inject } from '@angular/core';
import icVisibility from '@iconify/icons-ic/twotone-visibility';
import icVisibilityOff from '@iconify/icons-ic/twotone-visibility-off';
import { UntypedFormBuilder, UntypedFormGroup, Validators, UntypedFormControl, FormGroupDirective, NgForm } from '@angular/forms';
import { Router } from '@angular/router';
import { fadeInUp400ms } from '../../../../@vex/animations/fade-in-up.animation';
import { itemService } from '../../../helpers/services/main.service';
import { MatSnackBar } from '@angular/material/snack-bar';
import { ErrorStateMatcher } from '@angular/material/core';
import { Observable } from 'rxjs';
import { map, startWith } from 'rxjs/operators';
import { AuthService } from '../helpers/auth.service';
import { splitFullName } from './signup-name';
export interface DialogData {
  user: any[];
}
/** Error when invalid control is dirty, touched, or submitted. */
export class MyErrorStateMatcher implements ErrorStateMatcher {
  isErrorState(control: UntypedFormControl | null, form: FormGroupDirective | NgForm | null): boolean {
    const isSubmitted = form && form.submitted;
    return !!(control && control.invalid && (control.dirty || control.touched || isSubmitted));
  }
}
@Component({
    selector: 'signUp',
    templateUrl: './signUp.component.html',
    styleUrls: ['./signUp.component.scss'],
    animations: [
        fadeInUp400ms
    ],
    standalone: false
})

export class SignUpComponent implements OnInit {
  emailFormControl = new UntypedFormControl('', [Validators.required, Validators.email]);
  matcher = new MyErrorStateMatcher();
  form: UntypedFormGroup;
  inputType = 'password';
  visible = false;
  valid = true;
  icVisibility = icVisibility;
  icVisibilityOff = icVisibilityOff;
  myControl = new UntypedFormControl();
  options: any[] = ['Admin', 'Vendor', 'Sales', 'Designer','Production','sourcing_manager']
  filteredOptions: Observable<any[]>;
  constructor(private router: Router,
    private fb: UntypedFormBuilder,
    private cd: ChangeDetectorRef,
    public auth: AuthService,
    public itemService: itemService,
    private _snackBar: MatSnackBar
  ) {

  }

  async ngOnInit() {
    let url = this.router.url
    let urlArray = url.split('/')
    let token = urlArray[urlArray.length - 1].toString()
    let invitedEmail = ''
    let invitedName = ''
    try {
      const data: any = await this.itemService.verifyAuthToken({ token: token, route: 'sign_up' }).toPromise();
      if (data.status) {
        this.valid = true
        invitedEmail = data.email || ''
        invitedName = data.name || ''
      } else {
        this.valid = false
      }
    } catch (err) {
      console.error('[SignUp] verifyAuthToken failed:', err);
    }

    this.filteredOptions = this.myControl.valueChanges.pipe(
      startWith(''),
      map(value => (typeof value === 'string' ? value : value)),
      map(value => (value ? this._filter(value) : this.options.slice())),
    );

    // Pre-populate the details the admin already entered on the invitation so the
    // invitee does not have to re-type them. The email is the invited address, so
    // it is shown read-only (see template); name is split best-effort into first/last.
    const { firstName, lastName } = splitFullName(invitedName)
    this.emailFormControl.setValue(invitedEmail)

    this.form = this.fb.group({
      firstName: [firstName, Validators.required],
      lastName: [lastName, Validators.required],
      email: this.emailFormControl,
      password: ['', Validators.required],
      passwordConfirm: ['', Validators.required],
      token: [token]

    });
  }
  private _filter(value: any): any[] {
    let filterValue;
    filterValue = value.toLowerCase();
    return this.options.filter(options => options.toLowerCase().includes(filterValue));
  }
  send() {
    if (this.form.value.firstName && this.form.value.lastName && this.form.value.email && this.form.value.password && this.form.value.passwordConfirm) {
      if (this.emailFormControl.valid) {
        if (this.form.value.password == this.form.value.passwordConfirm) {
          this.itemService.signup(this.form.value).subscribe((data: any) => {
            if (data.status == true) {
              this._snackBar.open('The user was successfully created.', 'Ok')
              window.location.href = "/login"
            } else {
              this._snackBar.open('There is already an account registered to this email.', 'Ok')
            }
          })
        } else {
          this._snackBar.open('The passwords do not match.', 'Ok')
        }
      } else {
        this._snackBar.open('The email is not valid.', 'Ok')
      }
    } else {
      this._snackBar.open('Please fill all the fields.', 'Ok')
    }
  }

  toggleVisibility() {
    if (this.visible) {
      this.inputType = 'password';
      this.visible = false;
      this.cd.markForCheck();
    } else {
      this.inputType = 'text';
      this.visible = true;
      this.cd.markForCheck();
    }
  }

  displayFn(data: any) {
    if (data) {
      if (data.title) {
        return data.title && data.title ? data.title : '';
      } else {
        return data && data ? data : '';
      }
    }
  }
}

