import { describe, expect, it } from '@jest/globals';
import { RequiredField, formatFieldList, missingFields, missingFieldsMessage } from './required-fields';

interface Sample {
  a?: string;
  b?: string;
  c?: string;
}

const FIELDS: ReadonlyArray<RequiredField<Sample>> = [
  { key: 'a', label: 'Alpha' },
  { key: 'b', label: 'Bravo' },
  { key: 'c', label: 'Charlie' },
];

describe('missingFields', () => {
  it('returns nothing when all fields are present', () => {
    expect(missingFields({ a: '1', b: '2', c: '3' }, FIELDS)).toEqual([]);
  });

  it('treats blank and whitespace-only values as missing, in order', () => {
    expect(missingFields({ a: '1', b: '', c: '   ' }, FIELDS)).toEqual(['Bravo', 'Charlie']);
  });

  it('returns every label when the value is null or undefined', () => {
    expect(missingFields(null, FIELDS)).toEqual(['Alpha', 'Bravo', 'Charlie']);
    expect(missingFields(undefined, FIELDS)).toEqual(['Alpha', 'Bravo', 'Charlie']);
  });
});

describe('formatFieldList', () => {
  it('formats one, two, and three labels readably', () => {
    expect(formatFieldList(['Alpha'])).toBe('Alpha');
    expect(formatFieldList(['Alpha', 'Bravo'])).toBe('Alpha and Bravo');
    expect(formatFieldList(['Alpha', 'Bravo', 'Charlie'])).toBe('Alpha, Bravo and Charlie');
  });
});

describe('missingFieldsMessage', () => {
  it('returns null when nothing is missing', () => {
    expect(missingFieldsMessage({ a: '1', b: '2', c: '3' }, FIELDS)).toBeNull();
  });

  it('uses singular wording for one missing field', () => {
    expect(missingFieldsMessage({ a: '1', b: '2', c: '' }, FIELDS)).toBe(
      'Please fill in the following field: Charlie.',
    );
  });

  it('uses plural wording and lists all missing fields', () => {
    expect(missingFieldsMessage({ a: '', b: '', c: '3' }, FIELDS)).toBe(
      'Please fill in the following fields: Alpha and Bravo.',
    );
  });
});

