import { missingSignUpFieldsMessage } from './signup-validation';

const complete = {
  firstName: 'Albert',
  lastName: 'Testing',
  email: 'u2giants@gmail.com',
  password: 'secret',
  passwordConfirm: 'secret',
};

describe('missingSignUpFieldsMessage', () => {
  it('returns null when every field is present', () => {
    expect(missingSignUpFieldsMessage(complete)).toBeNull();
  });

  it('names the single missing field with singular wording', () => {
    expect(missingSignUpFieldsMessage({ ...complete, lastName: '' })).toBe(
      'Please fill in the following field: Last Name.',
    );
  });

  it('names every missing field with plural wording', () => {
    expect(
      missingSignUpFieldsMessage({ ...complete, password: '', passwordConfirm: '' }),
    ).toBe('Please fill in the following fields: Password and Password (Confirm).');
  });

  it('does not require a Role (unlike Create New User)', () => {
    // The invitee form has no Role field; a complete form without one is valid.
    expect(missingSignUpFieldsMessage(complete)).toBeNull();
  });
});

