  let url = this.router.url
  let urlArray = url.split('/')
  let token = urlArray[urlArray.length - 1].toString()

  // Build the form synchronously so the template always has a real FormGroup to
  // bind to. If it were created only after the async token check below, the
  // inputs would render with no backing control and typed values (e.g. First
  // Name) would never reach form.value.
  this.form = this.fb.group({
    firstName: ['', Validators.required],
    lastName: ['', Validators.required],
    email: this.emailFormControl,
    password: ['', Validators.required],
    passwordConfirm: ['', Validators.required],
    token: [token]
  });

  this.filteredOptions = this.myControl.valueChanges.pipe(
    startWith(''),
    map(value => (typeof value === 'string' ? value : value)),
    map(value => (value ? this._filter(value) : this.options.slice())),
  );

  try {
    const data: any = await this.itemService.verifyAuthToken({ token: token, route: 'sign_up' }).toPromise();
    if (data.status) {
      this.valid = true
      // Pre-populate the details the admin already entered on the invitation so
      // the invitee does not have to re-type them. The email is the invited
      // address (read-only in the template); the single name is split
      // best-effort into first/last.
      const { firstName, lastName } = splitFullName(data.name || '')
      this.form.patchValue({ firstName, lastName, email: data.email || '' })
    } else {
      this.valid = false
    }
  } catch (err) {
    console.error('[SignUp] verifyAuthToken failed:', err);
  }
}

